  assertEqual(result.rows[0][""], null, "trailing empty field → null");
}

section("Edge case – quoted field containing newline (multi-line field)");
{
  const csv = `name,bio
"Alice","Line one
Line two"
"Bob","Simple"`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 2, "two rows despite embedded newline");
  assertEqual(
    result.rows[0]["bio"],
    "Line one\nLine two",
    "embedded newline preserved in field"
  );
  assertEqual(result.rows[1]["name"], "Bob", "row after multi-line field");
}

section("Edge case – completely empty fields row");
{
  const csv = "a,b,c\n,,";
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 1, "one row");
  assertEqual(result.rows[0]["a"], null, "empty → null (a)");
  assertEqual(result.rows[0]["b"], null, "empty → null (b)");
  assertEqual(result.rows[0]["c"], null, "empty → null (c)");
}

section("Edge case – many consecutive errors");
{
  const csv = "a,b\n1\n2\n3\n4,5";
  const result = parseCSV(csv);
  assertEqual(result.errors.length, 3, "three malformed rows");
  assertEqual(result.rows.length, 1, "one valid row");
  assertEqual(result.rows[0]["a"], 4, "valid row value");
}

section("Filter + aggregation chaining");
{
  const csv = `category,amount
food,10
drink,5
food,20
drink,15
food,30`;
  const result = parseCSV(csv);

  const foodSum = result
    .filter((r) => r["category"] === "food")
    .sum("amount");
  assertClose(foodSum, 60, 1e-9, "sum of food amounts");

  const drinkAvg = result
    .filter((r) => r["category"] === "drink")
    .average("amount");
  assertClose(drinkAvg, 10, 1e-9, "average of drink amounts");

  const foodCount = result
    .filter((r) => r["category"] === "food")
    .count();
  assertEqual(foodCount, 3, "count of food rows");
}

section("Mixed types in a single column");
{
  const csv = `v
42
hello
true
null
3.14`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["v"], 42, "number");
  assertEqual(result.rows[1]["v"], "hello", "string");
  assertEqual(result.rows[2]["v"], true, "boolean");
  assertEqual(result.rows[3]["v"], null, "null");
  assertClose(result.rows[4]["v"] as number, 3.14, 1e-9, "float");
}

section("Quoted fields preserve types as strings");
{
  // A quoted "42" is still parsed through coerce → becomes number
  // This is intentional – quoting protects commas/quotes, not types.
  const csv = `v\n"42"\n"true"\n"null"`;
  const result = parseCSV(csv);
  assertEqual(result.rows[0]["v"], 42, 'quoted "42" coerced to number');
  assertEqual(result.rows[1]["v"], true, 'quoted "true" coerced to boolean');
  assertEqual(result.rows[2]["v"], null, 'quoted "null" coerced to null');
}

section("Multiple errors with specific row numbers");
{
  const csv = `h1,h2,h3
a,b,c
d,e
f,g,h
i,j,k,l
m,n,o`;
  const result = parseCSV(csv);
  assertEqual(result.rows.length, 3, "three valid rows");
  assertEqual(result.errors.length, 2, "two errors");
  assertEqual(result.errors[0].row, 3, "first error at row 3");
  assertEqual(result.errors[1].row, 5, "second error at row 5");
}

section("skipEmptyLines option");
{
  const csv = "a\n\n1\n\n2\n\n";
  const resultSkip = parseCSV(csv, { skipEmptyLines: true });
  assertEqual(resultSkip.rows.length, 2, "skip empty lines → 2 rows");

  const resultKeep = parseCSV(csv, { skipEmptyLines: false });
  // Empty lines have 1 field (empty string) but header has 1 field too → they parse as rows with null
  assert(resultKeep.rows.length > 2, "keeping empty lines → more rows");
}

section("Real-world-ish CSV");
{
  const csv = `id,name,email,score,active
1,"Doe, Jane",jane@example.com,95.5,true
2,"O""Brien, Bob",bob@example.com,87,true
3,Carol,carol@example.com,,false
4,Dave,dave@example.com,72.3,true`;
  const result = parseCSV(csv);
  assertEqual(result.errors.length, 0, "no errors in well-formed data");
  assertEqual(result.rows.length, 4, "four rows");

  assertEqual(result.rows[0]["name"], "Doe, Jane", "comma in name");
  assertEqual(result.rows[1]["name"], 'O"Brien, Bob', "escaped quote in name");
  assertEqual(result.rows[2]["score"], null, "empty score → null");
  assertEqual(result.rows[2]["active"], false, "inactive user");

  const activeAvg = result
    .filter((r) => r["active"] === true)
    .average("score");
  // Active scores: 95.5, 87, 72.3 → average = 254.8 / 3 ≈ 84.933...
  assertClose(activeAvg, 84.9333, 0.001, "average score of active users");

  const byActive = result.groupBy("active");
  assertEqual(byActive.get(true)!.length, 3, "3 active users");
  assertEqual(byActive.get(false)!.length, 1, "1 inactive user");
}

// ─── Summary ────────────────────────────────────────────────────────────────

console.log("\n" + "═".repeat(60));
console.log(`Results: ${passed} passed, ${failed} failed`);
if (failures.length > 0) {
  console.log("\nFailures:");
  for (const f of failures) {
    console.log(`  • ${f}`);
  }
  process.exit(1);
} else {
  console.log("\nAll tests passed! ✅");
  process.exit(0);
}

