// ─── Types ───────────────────────────────────────────────────────────────────

export interface CSVOptions {
  delimiter?: string;
  quote?: string;
  lineSeparator?: string;
  skipEmptyLines?: boolean;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Record<string, unknown>[];
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<unknown, Record<string, unknown>[]>;
}

// ─── Helpers ─────────────────────────────────────────────────────────────────

/**
 * Coerce a raw string token into a typed value.
 *
 * Conversion priority:
 *   1. null  – empty string, "null", "NULL"
 *   2. boolean – "true"/"false" (case-insensitive)
 *   3. number – anything that `Number()` accepts (but not empty string / whitespace-only)
 *   4. string – everything else
 */
function coerce(raw: string): unknown {
  // Null variants
  if (raw === "" || raw.toLowerCase() === "null") {
    return null;
  }

  // Booleans (case-insensitive)
  if (raw.toLowerCase() === "true") return true;
  if (raw.toLowerCase() === "false") return false;

  // Numbers – reject whitespace-only strings which Number("") === 0
  const trimmed = raw.trim();
  if (trimmed.length > 0 && !isNaN(Number(trimmed)) && isFinite(Number(trimmed))) {
    return Number(trimmed);
  }

  return raw;
}

/**
 * Parse a single CSV line respecting quoted fields.
 *
 * Returns an array of raw string tokens, or throws if a quote is unterminated.
 */
function parseLine(
  line: string,
  delimiter: string,
  quote: string
): string[] {
  const fields: string[] = [];
  let i = 0;
  const len = line.length;

  while (i <= len) {
    if (i === len) {
      // Trailing delimiter produced an empty final field
      // (only push if we already consumed at least one field AND the previous
      //  char was a delimiter – handled naturally below)
      // Actually, just break; the last field was already pushed.
      break;
    }

    if (line[i] === quote) {
      // ── Quoted field ──────────────────────────────────────────────────
      i++; // skip opening quote
      let value = "";
      let closed = false;

      while (i < len) {
        if (line[i] === quote) {
          // Peek next character
          if (i + 1 < len && line[i + 1] === quote) {
            // Escaped quote ("")
            value += quote;
            i += 2;
          } else {
            // Closing quote
            i++; // skip closing quote
            closed = true;
            break;
          }
        } else {
          value += line[i];
          i++;
        }
      }

      if (!closed && i >= len) {
        // We reached end-of-line inside a quoted field – that's unterminated
        throw new Error("Unterminated quoted field");
      }

      fields.push(value);

      // After the closing quote we expect either a delimiter or end-of-line
      if (i < len) {
        if (line[i] === delimiter) {
          i++; // consume delimiter
          // If delimiter is at end-of-line, push one more empty field
          if (i === len) {
            fields.push("");
          }
        } else {
          throw new Error(
            `Unexpected character '${line[i]}' after closing quote at position ${i}`
          );
        }
      }
    } else {
      // ── Unquoted field ────────────────────────────────────────────────
      const start = i;
      while (i < len && line[i] !== delimiter) {
        i++;
      }
      fields.push(line.substring(start, i));

      if (i < len) {
        // We stopped on a delimiter – consume it
        i++;
        // Trailing delimiter → empty field
        if (i === len) {
          fields.push("");
        }
      }
    }
  }

  return fields;
}

// ─── Result builder ──────────────────────────────────────────────────────────

function buildResult(
  rows: Record<string, unknown>[],
  headers: string[],
  errors: CSVError[]
): CSVResult {
  return {
    rows,
    headers,
    errors,

    filter(predicate: (row: Record<string, unknown>) => boolean): CSVResult {
      return buildResult(rows.filter(predicate), headers, errors);
    },

    sum(column: string): number {
      let total = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
        }
      }
      return total;
    },

    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const v = row[column];
        if (typeof v === "number") {
          total += v;
          count++;
        }
      }
      return count === 0 ? 0 : total / count;
    },

    count(): number {
      return rows.length;
    },

    groupBy(column: string): Map<unknown, Record<string, unknown>[]> {
      const map = new Map<unknown, Record<string, unknown>[]>();
      for (const row of rows) {
        const key = row[column];
        let group = map.get(key);
        if (!group) {
          group = [];
          map.set(key, group);
        }
        group.push(row);
      }
      return map;
    },
  };
}

// ─── Main entry point ────────────────────────────────────────────────────────

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  const delimiter = options?.delimiter ?? ",";
  const quote = options?.quote ?? '"';
  const skipEmpty = options?.skipEmptyLines ?? true;

  // ── Split into lines ────────────────────────────────────────────────────
  let lines: string[];
  if (options?.lineSeparator) {
    lines = input.split(options.lineSeparator);
  } else {
    // Auto-detect: split on \r\n, \r, or \n
    lines = input.split(/\r\n|\r|\n/);
  }

  // Handle quoted fields that span multiple lines by re-joining them.
  // A line with an odd number of *unescaped* quotes is the start (or
  // continuation) of a multi-line quoted field.
  const mergedLines: string[] = [];
  let buffer: string | null = null;
  const lineSep = options?.lineSeparator ?? "\n";

  for (const line of lines) {
    if (buffer !== null) {
      buffer += lineSep + line;
    } else {
      buffer = line;
    }

    // Count unescaped quotes
    let quoteCount = 0;
    for (let i = 0; i < buffer.length; i++) {
      if (buffer[i] === quote) quoteCount++;
    }
    // Escaped quotes ("") always come in pairs, so an even total means all
    // quotes are balanced (every open has a close).
    if (quoteCount % 2 === 0) {
      mergedLines.push(buffer);
      buffer = null;
    }
  }
  // If there's a dangling buffer, push it as-is (will generate an error later)
  if (buffer !== null) {
    mergedLines.push(buffer);
  }

  // Optionally skip empty lines
  const filteredLines = skipEmpty
    ? mergedLines.filter((l) => l.length > 0)
    : mergedLines;

  if (filteredLines.length === 0) {
    return buildResult([], [], []);
  }

  // ── Parse header row ────────────────────────────────────────────────────
  let headers: string[];
  try {
    headers = parseLine(filteredLines[0], delimiter, quote);
  } catch {
    // If even the header row is broken, return empty with an error
    return buildResult([], [], [
      { row: 1, message: "Failed to parse header row" },
    ]);
  }

  // ── Parse data rows ────────────────────────────────────────────────────
  const rows: Record<string, unknown>[] = [];
  const errors: CSVError[] = [];

  for (let idx = 1; idx < filteredLines.length; idx++) {
    const lineNum = idx + 1; // 1-based (header is row 1)

    let fields: string[];
    try {
      fields = parseLine(filteredLines[idx], delimiter, quote);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : String(err);
      errors.push({ row: lineNum, message: msg });
      continue;
    }

    if (fields.length !== headers.length) {
      errors.push({
        row: lineNum,
        message: `Expected ${headers.length} fields but got ${fields.length}`,
      });
      continue;
    }

    const obj: Record<string, unknown> = {};
    for (let c = 0; c < headers.length; c++) {
      obj[headers[c]] = coerce(fields[c]);
    }
    rows.push(obj);
  }

  return buildResult(rows, headers, errors);
}
